import React from "react";

import Link from "./Link";

/**
 * @prop {String} title
 * @prop {String} tagline
 * @prop {String} description
 * @prop {String} image
 * @prop {Number} minWidth
 * @prop {Number} maxWidth
 * @prop {Number} minHeight
 * @prop {Number} maxHeight
 * @prop {Number} imageWidth
 * @prop {Number} imageHeight
 * @prop {Boolean} dark
 * @prop {Boolean} center
 * @prop {Boolean} middle
 */

export default (props) => (
    <div className="Card" css={{
        display: "flex",
        flexDirection: "column",
        justifyContent: props.middle ? "center" : "initial",
        margin: 20,
        minWidth: props.minWidth,
        maxWidth: props.maxWidth,
        minHeight: props.minHeight,
        maxHeight: props.maxHeight,
        borderRadius: 5,
        boxShadow: "0 15px 25px -8px rgba(0, 0, 0, .1)",
        color: props.dark ? "var(--light)" : "var(--dark-but-not-black)",
        background: props.dark ? "linear-gradient(225deg, #23272A, #13171A)" : "var(--bastion-light-gradient)",
        transform: "translateZ(0)",
        transition: "all var(--transition-default-time) cubic-bezier(.175,.885,.32,1.275)",
        ":hover": {
            boxShadow: "0 20px 30px -8px rgba(0, 0, 0, .1)",
            transform: "translateY(-10px)",
            filter: "brightness(110%)",
        },
        ":hover > a .Card-details img": {
            filter: "none",
        },
        ":active": {
            boxShadow: "0 10px 20px -8px rgba(0, 0, 0, .1)",
            transform: "scale3d(.95,.95,.95) translateY(5px)",
            filter: "brightness(95%)",
        },
    }}>
        <Link to={ props.link } css={{
            display: "flex",
            padding: "20px 40px",
            height: "100%",
            width: "100%",
            justifyContent: props.middle ? "center" : "initial",
        }}>
            <div className="Card-details" css={{
                textAlign: props.center ? "center" : "initial",
            }}>
                {
                    props.image
                    ? <img
                        src={ props.image }
                        alt={ props.title }
                        height={ props.imageHeight ? props.imageHeight : "auto" }
                        width={ props.imageWidth ? props.imageWidth : "auto" }
                        css={{
                            maxWidth: "100%",
                            maxHeight: "100%",
                            filter: props.monochrome ? "saturate(0) brightness(10%)" : "none",
                            transition: "filter var(--transition-default-time) ease",
                        }}
                    />
                    : <></>
                }
                <h4 css={{
                    margin: "20px 0",
                    fontWeight: 500,
                }}>
                    { props.title }
                </h4>
                <p css={{ opacity: .8 }}>
                    { props.tagline }
                </p>
                <p>
                    { props.description }
                </p>
            </div>
        </Link>
    </div>
);
