import React from "react";
import { css } from "glamor";

import Link from "../Link";
import navigation from "../../data/navigation.yaml";

const opened = css({
    opacity: 1,
    transform: "scale(1) translateY(0) !important",
});
const closed = css({
    opacity: 0,
    transform: "scale(.9) translateY(-10px)",
    pointerEvents: "none",
});

function openNav(i) {
    if (document) {
        let element = document.querySelector(`.MoreLinks-${i} ul`);
        element.classList.remove(`${closed}`);
        element.classList.add(`${opened}`);
    }
}
function closeNav(i) {
    if (document) {
        let element = document.querySelector(`.MoreLinks-${i} ul`);
        element.classList.add(`${closed}`);
        element.classList.remove(`${opened}`);
    }
}

export default () => (
    <div css={{
        display: "flex",
        alignItems: "center",
        marginRight: "15px",
        zIndex: 10,
    }}>
        <ul css={{
            listStyle: "none",
            margin: 0,
            padding: 0,
        }}>
            {
                navigation.header.left.map((item, i) => {
                    if (item.more) {
                        return (
                            <li
                                key={ i }
                                className={ "MoreLinks-" + i }
                                css={{
                                    padding: "10px 15px",
                                    display: "inline-block",
                                    color: item.button ? "var(--dark-but-not-black)" : "var(--light)",
                                    transform: "translateZ(0px)",
                                    transition: "filter var(--transition-default-time) ease, color var(--transition-default-time) ease",
                                    ":hover": {
                                        color: item.button ? "var(--black)" : "var(--white)",
                                        filter: "brightness(110%)",
                                    },
                                }}
                                onMouseEnter={ () => openNav(i) }
                                onMouseLeave={ () => closeNav(i) }
                            >
                                <span css={{
                                    display: "flex",
                                    cursor: "pointer",
                                    ":after": {
                                        content: "\u2039",
                                        transform: "rotateZ(-90deg) translateX(3px)",
                                        width: 16,
                                        height: "100%",
                                        alignSelf: "center",
                                        marginLeft: 5,
                                    },
                                }}>
                                    { item.name }
                                </span>
                                <ul
                                    className={ `${closed}` }
                                    css={{
                                        position: "absolute",
                                        minWidth: 122,
                                        listStyle: "none",
                                        marginTop: "10px",
                                        padding: "3px",
                                        background: "var(--bastion-light-gradient)",
                                        borderRadius: "3px",
                                        boxShadow: "0 15px 25px -8px rgba(0, 0, 0, .1)",
                                        transition: "opacity .143s ease, transform .143s ease",
                                    }}
                                >
                                    {
                                        item.more.map((subItem, i) => (
                                            <Link to={ subItem.link } key={ i }>
                                                <li css={{
                                                    padding: "5px 10px",
                                                    color: "var(--somewhat-dark)",
                                                    fontSize: ".9em",
                                                    borderRadius: "3px",
                                                    ":hover": {
                                                        color: "var(--dark-but-not-black)",
                                                        backgroundColor: "#eee"
                                                    }
                                                }}>
                                                    { subItem.name }
                                                </li>
                                            </Link>
                                        ))
                                    }
                                </ul>
                            </li>
                        );
                    } else {
                        return (
                            <Link to={ item.link } key={ i }>
                                <li css={{
                                    padding: "10px 15px",
                                    display: "inline-block",
                                    color: item.button ? "var(--dark-but-not-black)" : "var(--light)",
                                    borderRadius: "3px",
                                    background: item.button ? "var(--bastion-accent-gradient)" : "none",
                                    transform: "translateZ(0px)",
                                    transition: "filter var(--transition-default-time) ease, color var(--transition-default-time) ease",
                                    ":hover": {
                                        color: item.button ? "var(--black)" : "var(--white)",
                                        filter: "brightness(110%)",
                                    },
                                }}>
                                    { item.name }
                                </li>
                            </Link>
                        );
                    }
                })
            }
        </ul>
    </div>
);
