import React from "react";

import isBrowser from "../utils/isBrowser";
import notice from "../data/notice.yaml";

export default class extends React.Component {
    state = {
        noticeViewed: false,
    };

    render = () => (
        <div
            onClick={ () => {
                this.setState({ noticeViewed: true });
                isBrowser() && window.sessionStorage.setItem("noticeViewed", true);
            }}
            css={{
                maxWidth: 800,
                display: this.state.noticeViewed || (isBrowser() && window.sessionStorage.getItem("noticeViewed")) ? "none" : "flex",
                flexDirection: "column",
                justifyContent: "center",
                alignItems: "center",
                position: "fixed",
                left: "50%",
                bottom: 30,
                padding: 20,
                transform: "translate(-50%)",
                color: "var(--black)",
                fontSize: ".9em",
                textAlign: "center",
                border: "2px solid var(--iris)",
                borderRadius: 5,
                background: "var(--bastion-accent-gradient)",
                boxShadow: "0 10px 20px -15px rgba(0, 0, 0, .3)",
                transition: "opacity .125s ease-out, filter .125s ease-out, transform .125s ease-out",
                cursor: "pointer",
                zIndex: 20,
                ":hover": {
                    boxShadow: "0 20px 30px -15px rgba(0, 0, 0, .1)",
                    transform: "translate(-50%) translateY(-10px)",
                    filter: "brightness(105%)",
                },
                ":active": {
                    transform: "translate(-50%) scale(.8)",
                    opacity: .3,
                },
                "& a": {
                    fontWeight: 500,
                    borderBottom: "1px solid var(--black)",
                    pointerEvents: "auto",
                },
                "& *": {
                    pointerEvents: "none",
                }
            }}
        >
            <div css={{ fontWeight: 500 }} dangerouslySetInnerHTML={{ __html: notice.title }} />
            <div dangerouslySetInnerHTML={{ __html: notice.description }} />
        </div>
    );
};
