import React from "react";
import Link from "../Link";
import navigation from "../../data/navigation.yaml";

const listStyle = {
    padding: "15px 15px",
    color: "#ddd",
    transform: "translateZ(0px)",
    transition: "color .2s ease, background-color .2s ease",
    ":hover": {
        color: "#fff",
        backgroundColor: "rgba(250, 250, 250, .01)",
    },
};

export default (props) => (
    <ul css={{
        listStyle: "none",
        display: "flex",
        margin: 0,
        padding: 0,
        height: "100vh",
        flexDirection: "column",
        textAlign: "center",
        overflowY: "auto",
        zIndex: 10,
        background: "linear-gradient(135deg, #050505, #070A0C)",
        transform: props.open ? "translateY(0) translateZ(0)" : "translateX(50px) translateZ(0)",
        opacity: props.open ? 1 : 0,
        transition: "opacity .2s cubic-bezier(.175,.885,.32,1.275), transform .2s cubic-bezier(.175,.885,.32,1.275)",
    }}>
        <Link to="/">
            <li css={{ ...listStyle }}>Home</li>
        </Link>
        {
            navigation.header.left.map((item, i) => {
                if (item.more) {
                    return (
                        <>
                        {
                            item.more.map((subItem, i) => (
                                <Link to={ subItem.link } key={ i }>
                                    <li css={{ ...listStyle }}>{ subItem.name }</li>
                                </Link>
                            ))
                        }
                        </>
                    );
                } else {
                    return (
                        <Link to={ item.link } key={ i }>
                            <li css={{ ...listStyle }}>{ item.name }</li>
                        </Link>
                    );
                }
            })
        }
        {
            navigation.header.right.map((item, i) => (
                <Link to={ item.link } key={ i }>
                    <li css={{ ...listStyle }}>{ item.name }</li>
                </Link>
            ))
        }
    </ul>
);
